def assess(record: dict) -> str:
    required = {'blob_store', 'cache_authoritative', 'cache_ttl_s', 'case_id', 'transactions'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    meets = record["cache_authoritative"] or record["transactions"] != "cache"
    return "PASS" if meets else 'REDESIGN_PERSISTENCE'

